Build an advanced concurrency system that surpasses both Go's goroutines and Rust's threading model:

1. Actor System:
   ```goo
   actor Counter {
       value: int

       handle Increment() -> int {
           self.value++
           return self.value
       }

       handle GetValue() -> int {
           return self.value
       }
   }

   // Usage is completely safe
   counter := Counter.spawn()
   future_value := counter.send(Increment())
   result := future_value.await() // Type-safe, deadlock-free
