   func batch_process<T>(items: []T, processor: Processor<T>) []T {
       result := make([]T, len(items))
       parallel for i, item := range items {
           result[i] = processor.process(item)
       }
       return result
   } // Compiler automatically infers all necessary constraints
   ```

