     fn curl_easy_init() -> *CURL
     fn curl_easy_setopt(curl: *CURL, option: CURLoption, parameter: any) -> CURLcode
     fn curl_easy_perform(curl: *CURL) -> CURLcode
     fn curl_easy_cleanup(curl: *CURL)
   }

